<script setup lang="ts">
import {onMounted,ref}from'vue';import{scanAttendanceQr}from'../lib/attendanceScanner';import{staffAttendance,submitAttendanceScan,type AttendanceRecord,type AttendanceScan}from'../lib/api';
const attendance=ref<AttendanceRecord|null>(null),pending=ref<AttendanceScan|null>(null),error=ref(''),notice=ref(''),working=ref(false);async function load(){try{const data=await staffAttendance();attendance.value=data.attendance;pending.value=data.pending_scan}catch{error.value='Attendance status could not load.'}}async function scan(){working.value=true;error.value='';notice.value='';try{const result=await submitAttendanceScan(await scanAttendanceQr());pending.value=result.data;notice.value=result.message}catch(reason){error.value=reason instanceof Error?reason.message:'Attendance scan failed. Please ask an administrator for help.'}finally{working.value=false}}onMounted(load)
</script>
<template><section class="attendance"><h2>Attendance</h2><p v-if="attendance">{{attendance.time_in_at?'Time in: '+new Date(attendance.time_in_at).toLocaleTimeString():'Not clocked in'}}<span v-if="attendance.time_out_at"> · Time out: {{new Date(attendance.time_out_at).toLocaleTimeString()}}</span></p><p v-else>Not clocked in today.</p><p v-if="pending||notice" class="notice">{{notice||'Your scan is awaiting on-site confirmation.'}}</p><p v-if="error" class="alert">{{error}}</p><button :disabled="working||!!pending||attendance?.status==='closed'" @click="scan">{{working?'Opening camera…':pending?'Awaiting confirmation':'Scan attendance QR'}}</button><small>Ask an admin or receptionist to verify you after scanning.</small></section></template>
<style scoped>.attendance{display:grid;gap:.55rem;margin:1rem 0;padding:1rem;border:1px solid var(--casa-border);border-radius:1rem;background:var(--casa-paper)}h2{margin:0;font-family:var(--font-display);color:var(--casa-deep-palm)}button{min-height:48px;border:0;border-radius:.7rem;background:var(--casa-deep-palm);color:white;font-weight:800}small{color:var(--casa-muted)}</style>
